/**
 * @summary List testimonials
 */
export const getListTestimonialsUrl = (params?: ListTestimonialsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/testimonials?${stringifiedParams}`
    : `/api/testimonials`;
};

export const listTestimonials = async (
  params?: ListTestimonialsParams,
  options?: RequestInit,
): Promise<TestimonialListResponse> => {
  return customFetch<TestimonialListResponse>(getListTestimonialsUrl(params), {
    ...options,
    method: "GET",
  });
};

